      // Compute the new constant based on the predicate
      APFloat NewC(SrcSem);
      bool Transform = false;

      switch (Pred) {
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_OLT: {
        // For oge: fcmp oge (fptrunc X), C -> fcmp oge X, C'
        //   where C' is the smallest value that truncates to C
        //   This is the midpoint between prev_float(C) and C
        // For olt: fcmp olt (fptrunc X), C -> fcmp olt X, C'
        //   where C' is the largest value that truncates to < C
        //   This is also the midpoint between prev_float(C) and C
        APFloat PrevC = DstC;
        PrevC.next(true); // nextDown
        // Convert PrevC and DstC to SrcSem for computation
        bool Ignore;
        PrevC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignore);
        NewC = DstC;
        NewC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignore);
        NewC.add(PrevC, APFloat::rmNearestTiesToEven);
        NewC.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
        Transform = true;
        break;
      }
      case FCmpInst::FCMP_OGT:
      case FCmpInst::FCMP_OLE: {
        // For ogt: fcmp ogt (fptrunc X), C -> fcmp ogt X, C'
        //   where C' is the smallest value that truncates to > C
        //   This is the midpoint between C and next_float(C)
        // For ole: fcmp ole (fptrunc X), C -> fcmp ole X, C'
        //   where C' is the largest value that truncates to C
        //   This is also the midpoint between C and next_float(C)
        APFloat NextC = DstC;
        NextC.next(false); // nextUp
        // Convert NextC and DstC to SrcSem for computation
        bool Ignore;
        NextC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignore);
        NewC = DstC;
        NewC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignore);
        NewC.add(NextC, APFloat::rmNearestTiesToEven);
        NewC.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
        Transform = true;
        break;
      }
      default:
        break;
      }

      if (Transform) {
        Constant *NewCVal = ConstantFP::get(X->getType(), NewC);
        return new FCmpInst(Pred, X, NewCVal, "", &I);
      }
    }
  }
